mapper.update:
update fin_profit_share_record
status=#{status}, update_by=#{updateBy}, update_time=sysdate(), remark=#{remark},
where share_id=#{shareId}

mapper.select:
select ifnull(sum(manager_profit_amount + investor_profit_amount), 0)
from fin_profit_share_record
where del_flag = '0'

    and dept_id in

        #{deptId}



    and share_time >= #{startTime}


    and share_time <= #{endTime}

select ifnull(sum(manager_profit_amount), 0)
from fin_profit_share_record
where del_flag = '0'

    and dept_id in

        #{deptId}



    and share_time >= #{startTime}


    and share_time <= #{endTime}

select ifnull(sum(investor_profit_amount), 0)
from fin_profit_share_record
where del_flag = '0'

    and dept_id in

        #{deptId}



    and share_time >= #{startTime}


    and share_time <= #{endTime}

select s.dept_id as deptId, d.dept_name as deptName, ifnull(sum(s.manager_profit_amount), 0) as amount from fin_profit_share_record s left join sys_dept d on s.dept_id = d.dept_id where s.del_flag = '0'
and s.dept_id in
#{deptId}
and s.share_time >= #{startTime}
and s.share_time <= #{endTime}
group by s.dept_id, d.dept_name order by amount desc

select s.dept_id as deptId, d.dept_name as deptName, ifnull(sum(s.investor_profit_amount), 0) as amount from fin_profit_share_record s left join sys_dept d on s.dept_id = d.dept_id where s.del_flag = '0'
and s.dept_id in
#{deptId}
and s.share_time >= #{startTime}
and s.share_time <= #{endTime}
group by s.dept_id, d.dept_name order by amount desc

select date_format(s.share_time, '%Y-%m-%d') as dateStr, s.dept_id as deptId, d.dept_name as deptName, ifnull(sum(s.manager_profit_amount + s.investor_profit_amount), 0) as totalAmount, ifnull(sum(s.manager_profit_amount), 0) as managerAmount, ifnull(sum(s.investor_profit_amount), 0) as investorAmount from fin_profit_share_record s left join sys_dept d on s.dept_id = d.dept_id where s.del_flag = '0'
and s.dept_id in
#{deptId}
and s.share_time >= #{startTime}
and s.share_time <= #{endTime}
group by date_format(s.share_time, '%Y-%m-%d'), s.dept_id, d.dept_name order by dateStr, s.dept_id
